struct Point {
    x: i32,
    y: i32,
}

fn main() {
    let y: Option<Point> = Some(Point { x: 100, y: 200 });

    match &y {
        Some(p) => println!("Co-ordinates are ({}, {})", p.x, p.y),
        _ => panic!("no match!"),
    };

    let optional_value: Option<i32> = None;

    let value = optional_value.unwrap_or(42);
    println!("Value: {value}");
    assert_eq!(value, 42);

    println!("y is still accessible: {:?}", y.is_some());
}
